contracts/MathLib.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity =0.8.30;
library MathLib {
    function bump(uint256 value) external pure returns (uint256) {
        return value + 7;
    }
}

contracts/Scale.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity =0.8.30;
library Scale {
    function local(uint256 value) internal pure returns (uint256) {
        return value * 3;
    }
}

contracts/Target.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity =0.8.30;
import {MathLib} from "./MathLib.sol";
import {Scale} from "./Scale.sol";
contract Target {
    address public immutable owner;
    uint256 public immutable seed;

    constructor(address owner_, uint256 seed_) {
        owner = owner_;
        seed = seed_;
    }

    function score(uint256 value) external view returns (uint256) {
        require(msg.sender == owner, "owner");
        return MathLib.bump(value) + Scale.local(seed);
    }
}
